				if (s[n - 1] == t[0]) {
					++cc;
					if (cc == 1) {
						sol[n][0][1] = 0;
					} else {
						try_update_sol(n, 0, cc, sol[n - 1][0][cc - 1]);
					}
				} else if (s[n - 1] == t[1]) {
					try_update_sol(n, 0, cc, sol[n - 1][0][cc] + cc);
				} else {
					try_update_sol(n, 0, cc, sol[n - 1][0][cc]);
				}
				for (int k = cc; k <= K; ++k) {
					try_update_sol(n, k, 0, 0);
				}
			}			
		}
