		// 		if (s[n - 1] == t[0]) {
		// 			++cc;
		// 			try_update_sol(n, k, 1, sol[n - 1][k - 1][1] + 1);
		// 		} else if (s[n - 1] == t[1]) {
		// 			try_update_sol(n, k, 1, sol[n - 1][k][1] + 1);
		// 		} else {
		// 			try_update_sol(n, k, 1, sol[n - 1][k][1]);					
		// 			try_update_sol(n, k, 1, sol[n - 1][k - 1][1] + 1);
		// 		}
