		for (int k = 1; k <= K; ++k) {
			try_update_sol(1, k, 1, 0);
			for (int n = 2; n <= N; ++n) {
				for (int i = 1; i <= n; ++i) {
					try_update_sol(n, k, i, sol[n][k - 1][i]);
					if (s[n - 1] == t[0]) {
						try_update_sol(n, k, i, sol[n - 1][k][i - 1]);
