fn main() {
	let mut rin = reader();
	let mut rout = writer();
	const INF: i32 = 1000000000;

	l!(n,m = rin.u());
	l!(s,t = rin.vb());
	assert!(s.len() == n);
	if t[0] == t[1] {
		let c = s.into_iter().filter(|&x| x == t[0]).count();
		let x = n.min(c + m);
		let sol = if x <= 1 {0} else {x * (x-1) / 2};
		writeln!(rout, "{}", sol).ok();
		return;
	}
	let mut dp = v!([n+1][n+1][m+2] = -INF);
	dp[0][0][0] = 0;
	for i in 0..n {
		for j in 0..=i {
			for k in 0..=m.min(i) {
				let v = dp[i][j][k];
				if v < 0 {
					continue;
				}
				if s[i] == t[0] {
					max!(dp[i+1][j+1][k], v);
				} else {
					max!(dp[i+1][j+1][k+1], v);
				}
				if s[i] == t[1] {
					max!(dp[i+1][j][k], v + j as i32);
				} else {
					max!(dp[i+1][j][k+1], v + j as i32);
				}
				max!(dp[i+1][j][k], v);
			}
		}
	}
	let mut sol = 0;
	for j in 0..=n {
		for k in 0..=m {
			max!(sol, dp[n][j][k]);
		}
	}
	writeln!(rout, "{}", sol).ok();
}
